// Hand-written queries (NOT generated by sqlc).
//
// Hard-gate evaluation persistence for run_metric (migration 091): writing
// the gate_status/gate_detail computed by server/internal/gate, and listing
// rows for the re-evaluate endpoint (POST /api/metrics/reevaluate) which
// recomputes gates over stored rows when the rule set changes. Same style
// as run_metric_manual.go: const SQL, Params struct, method on *Queries.

package db

import (
	"context"

	"github.com/jackc/pgx/v5/pgtype"
)

const setRunMetricGate = `-- name: SetRunMetricGate :exec
UPDATE run_metric
SET gate_status = $2,
    gate_detail = $3
WHERE id = $1
`

// SetRunMetricGate stores the gate evaluation for one row. Empty status /
// nil detail map to SQL NULL ("not evaluated / insufficient data").
func (q *Queries) SetRunMetricGate(ctx context.Context, id pgtype.UUID, gateStatus pgtype.Text, gateDetail []byte) error {
	_, err := q.db.Exec(ctx, setRunMetricGate, id, gateStatus, gateDetail)
	return err
}

const listRunMetricsForGateReeval = `-- name: ListRunMetricsForGateReeval :many
SELECT ` + runMetricColumns + `
FROM run_metric
WHERE workspace_id = $1
  AND ($2::text IS NULL OR campaign = $2)
  AND ($3::uuid IS NULL OR issue_id = $3)
ORDER BY created_at DESC
`

type ListRunMetricsForGateReevalParams struct {
	WorkspaceID pgtype.UUID `json:"workspace_id"`
	Campaign    pgtype.Text `json:"campaign"`
	IssueID     pgtype.UUID `json:"issue_id"`
}

// ListRunMetricsForGateReeval returns every run_metric row matching the
// re-evaluate filters (no pagination: the endpoint must visit all of them).
func (q *Queries) ListRunMetricsForGateReeval(ctx context.Context, arg ListRunMetricsForGateReevalParams) ([]RunMetric, error) {
	rows, err := q.db.Query(ctx, listRunMetricsForGateReeval,
		arg.WorkspaceID,
		arg.Campaign,
		arg.IssueID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []RunMetric{}
	for rows.Next() {
		var i RunMetric
		if err := rows.Scan(
			&i.ID,
			&i.WorkspaceID,
			&i.ArtifactID,
			&i.TaskID,
			&i.IssueID,
			&i.Campaign,
			&i.Iteration,
			&i.Sharpe,
			&i.Sortino,
			&i.Calmar,
			&i.AnnReturn,
			&i.MaxDrawdown,
			&i.ProfitFactor,
			&i.OosSharpe,
			&i.OosWindows,
			&i.Timeframe,
			&i.Symbols,
			&i.Params,
			&i.Extra,
			&i.GateStatus,
			&i.GateDetail,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}
